css:
@import url("_global_style.css");

.mermaid-out {
  display: flex;
  justify-content: center;
  overflow-x: auto;
  min-height: 2rem;
}

.mermaid-out svg {
  max-width: 100%;
  height: auto;
}

.mermaid-src {
  display: none !important;
}

.mermaid-plain {
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 0.85em;
  white-space: pre-wrap;
  opacity: 0.75;
  margin-top: 0.5em;
}

.mermaid-err {
  text-align: left;
  font-size: 0.85em;
  white-space: pre-wrap;
  color: #c0392b;
  max-width: 100%;
}

.nightMode .mermaid-err {
  color: #e74c3c;
}
